  const [tenants, setTenants] = useState<Tenant[]>([
    { id: '1', companyName: 'SapiSoft Demo', industry: 'TECH', status: 'ACTIVE', subscriptionEnd: '31/12/2030', ownerName: 'Admin Demo', phone: '900000000', planType: 'FULL', baseCurrency: 'PEN' }
