      onAddProduct({ 
        ...newProduct, 
        id: 'P-' + Date.now(), 
        category: (newProduct.category || 'GENERAL').toUpperCase(),
        priceTiers: validTiers
      } as Product);
      setShowModal(false);
  };

  // ... (updateTier, handleRefreshStock remain same)

  const initiateDelete = (product: Product) => {
      if (!hasPermission('inv.delete')) return alert("⛔ ACCESO DENEGADO\n\nNo tiene permisos para eliminar productos.");
      setProductToDelete(product);
      setDeletePassword('');
      setShowDeleteAuth(true);
  };

  // ... (confirmDelete, handleExcelImport, handleExportData remain same)

  return (
    <div className="flex flex-col h-full space-y-3 md:space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      {/* ... (Import/Delete Modals) ... */}

