                  {filteredProducts.map(p => (
                     <tr key={p.id} className={`group transition-colors ${p.status === 'DISCONTINUED' ? 'bg-slate-100 dark:bg-slate-900 opacity-60' : 'hover:bg-slate-50/50 dark:hover:bg-slate-700'}`}>
                        {/* ... Columns ... */}
                        <td className="px-6 py-4 text-center">
                            <button 
                                onClick={() => initiateDelete(p)} 
                                className={`p-2 rounded-xl transition-all ${hasPermission('inv.delete') ? 'text-slate-300 hover:text-rose-500 hover:bg-rose-50' : 'text-slate-200 cursor-not-allowed'}`}
                                title={hasPermission('inv.delete') ? "Eliminar Producto" : "Sin permisos"}
                            >
                                <Trash2 size={18}/>
                            </button>
                        </td>
                     </tr>
                  ))}
               </tbody>
            </table>
         </div>
      </div>

      {/* ... Create/Edit Modal ... */}
    </div>
  );
