                </div>
                <div className="flex flex-wrap items-center justify-center gap-2 w-full md:w-auto">
                    <button onClick={() => setIsTransferModalOpen(true)} className="flex-1 md:flex-none px-3 py-1.5 bg-blue-600 text-white rounded-lg text-[10px] font-black uppercase flex items-center justify-center gap-1.5 shadow-sm"><ArrowRightLeft size={12}/> Transferir</button>

                    <button onClick={handleOpenClose} className={`flex-1 md:flex-none px-3 py-1.5 rounded-lg text-[10px] font-black uppercase flex items-center justify-center gap-1.5 shadow-sm ${hasPermission('cash.open_close') ? 'bg-slate-800 text-white' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}>
                        <Lock size={12}/> Cierre
