                    <button onClick={handleOpenIncome} className={`flex-1 md:flex-none px-3 py-1.5 rounded-lg text-[10px] font-black uppercase flex items-center justify-center gap-1.5 shadow-sm ${hasPermission('cash.income') ? 'bg-emerald-600 text-white' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}>
