const CashBoxManager = ({ type, expectedCash, bankBalances, onConfirm }: { type: 'OPEN' | 'CLOSE', expectedCash: number, bankBalances: Record<string, string>, onConfirm: any }) => {
    const [amount, setAmount] = useState(type === 'OPEN' ? '' : '');
