            onConfirm(val, expectedCash, 0, notes, bankBalances || {});
        }
    };

    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-8 max-w-md w-full border border-slate-200 dark:border-slate-700 animate-in zoom-in-95">
