                    expectedCash={currentCashBalance} 
                    bankBalances={bankBalancesInfo} 
                    onConfirm={(counted: number, sysCash: number, sysDig: number, note: string, banks: any) => {
                        onCloseCashBox(counted, sysCash, sysDig, note, banks);
                        setIsCloseModalOpen(false);
                    }} 
                />
            </div>
        )}

        {(isIncomeModalOpen || isExpenseModalOpen) && (
            <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-sm z-[2000] flex items-center justify-center p-4">
                <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl border border-white/20 animate-in zoom-in-95 overflow-hidden">
                    <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 flex justify-between items-center">
                        <h3 className="font-black text-sm uppercase tracking-widest text-slate-800 dark:text-white flex items-center gap-2">
                            {isIncomeModalOpen ? <Plus size={18} className="text-emerald-500"/> : <Minus size={18} className="text-orange-500"/>}
                            {isIncomeModalOpen ? 'Registrar Ingreso' : 'Registrar Gasto'}
                        </h3>
                        <button onClick={() => { setIsIncomeModalOpen(false); setIsExpenseModalOpen(false); }} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full transition-colors"><X size={18}/></button>
                    </div>
                    <div className="p-8 space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Monto</label>
                            <input 
                                type="number" 
                                autoFocus
                                className="w-full p-4 bg-slate-50 dark:bg-slate-950 border-2 border-slate-100 dark:border-slate-800 rounded-2xl text-2xl font-black text-slate-800 dark:text-white outline-none focus:border-blue-500 transition-colors"
                                placeholder="0.00"
                                value={movementForm.amount}
                                onChange={e => setMovementForm({...movementForm, amount: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Concepto / Descripción</label>
                            <input 
                                type="text" 
                                className="w-full p-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold uppercase outline-none focus:border-blue-500 transition-colors"
                                placeholder="Ej. Venta de cartón, Pago de luz..."
                                value={movementForm.description}
                                onChange={e => setMovementForm({...movementForm, description: e.target.value})}
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Categoría</label>
                                <select 
                                    className="w-full p-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold uppercase outline-none"
                                    value={movementForm.category}
                                    onChange={e => setMovementForm({...movementForm, category: e.target.value})}
                                >
                                    <option value="">-- General --</option>
                                    {(isIncomeModalOpen ? fixedIncomeCategories : fixedExpenseCategories).map(c => (
                                        <option key={c} value={c}>{c}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Método</label>
                                <select 
                                    className="w-full p-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold uppercase outline-none"
                                    value={movementForm.method}
                                    onChange={e => setMovementForm({...movementForm, method: e.target.value as any})}
                                >
                                    <option value="Efectivo">Efectivo</option>
                                    <option value="Transferencia">Transferencia</option>
                                    <option value="Yape">Yape</option>
                                </select>
                            </div>
                        </div>

                        <button 
                            onClick={() => handleSubmitMovement(isIncomeModalOpen ? 'Ingreso' : 'Egreso')}
                            className={`w-full py-4 mt-2 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl active:scale-95 transition-all ${isIncomeModalOpen ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-orange-600 hover:bg-orange-700'}`}
                        >
                            Guardar Movimiento
                        </button>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default CashModule;
